def dodaj(a, b):
    return a + b                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                        
def podziel(a, b):                                                                                                                                                                                                                                                                      
    if b ==0:                                                                                                                                                                                                                                                                           
        raise ValueError("Dzielenie przez zero")                                                                                                                                                                                                                                        
    return a / b
